import React from 'react';
import { Link, NavLink, useLocation, useNavigate } from 'react-router-dom';
import { Mail, Phone, Package } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

const navItems = [
  { label: 'Services', to: '#services' },
  { label: 'Track', to: '#track' },
  { label: 'Book a Post', to: '#book' },
  { label: 'Locate Us', to: '#offices' },
];

export default function SiteNavbar() {
  const { isAuthenticated, user, logout } = useAuth();
  const navigate = useNavigate();
  const { pathname } = useLocation();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <header className="shadow-sm bg-white position-sticky top-0 z-3">
      <div className="bg-primary text-white py-1 small">
        <div className="container d-flex justify-content-between">
          <span className="d-flex align-items-center gap-2">
            <Phone size={16} /> 1800-266-6868
          </span>
          <span className="d-flex align-items-center gap-2">
            <Mail size={16} /> support@dakkhana.gov.in
          </span>
        </div>
      </div>
      <nav className="container py-3 d-flex align-items-center justify-content-between flex-wrap gap-3">
        <Link to="/" className="d-flex align-items-center gap-2 text-decoration-none">
          <div className="bg-danger text-white rounded-circle p-2">
            <Package size={26} />
          </div>
          <div>
            <div className="fw-bold text-dark">Dakkhana Post</div>
            <div className="small text-muted">Serving Bharat since 1854</div>
          </div>
        </Link>
        <div className="d-flex align-items-center gap-3 flex-wrap">
          {navItems.map((item) =>
            pathname === '/' ? (
              <a key={item.to} href={item.to} className="text-muted text-decoration-none fw-medium">
                {item.label}
              </a>
            ) : (
              <NavLink key={item.to} to={`/${item.to}`} className="text-muted text-decoration-none fw-medium">
                {item.label}
              </NavLink>
            )
          )}
        </div>
        <div className="d-flex align-items-center gap-2">
          {isAuthenticated ? (
            <>
              <span className="text-muted small text-end">
                Logged in as <br />
                <strong>{user?.name}</strong>
              </span>
              <button className="btn btn-outline-secondary btn-sm" onClick={handleLogout}>
                Logout
              </button>
              <Link
                to={user?.role === 'admin' ? '/dashboard/admin' : '/dashboard/customer'}
                className="btn btn-primary btn-sm"
              >
                Dashboard
              </Link>
            </>
          ) : (
            <>
              <Link to="/login" className="btn btn-outline-secondary btn-sm">
                Login
              </Link>
              <Link to="/register" className="btn btn-primary btn-sm">
                Open Account
              </Link>
            </>
          )}
        </div>
      </nav>
    </header>
  );
}
